import { useState, useEffect } from 'react';
import { patientAPI } from '../../utils/api';
import { useApp } from '../../context/AppContext';
import toast from 'react-hot-toast';

const STATUS_BADGE = {
  Pending: 'badge-pending', Approved: 'badge-approved',
  Completed: 'badge-completed', Cancelled: 'badge-cancelled', Rescheduled: 'badge-rescheduled'
};

export default function PatientAppointments() {
  const { patientId } = useApp();
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [rescheduleModal, setRescheduleModal] = useState(null);
  const [newDate, setNewDate] = useState('');
  const [newTime, setNewTime] = useState('');
  const [slots, setSlots] = useState([]);

  useEffect(() => { if (patientId) load(); }, [patientId]);

  const load = async () => {
    try {
      const res = await patientAPI.getAppointments(patientId);
      setAppointments(res.data);
    } catch { toast.error('Failed to load appointments'); }
    finally { setLoading(false); }
  };

  const handleCancel = async (id) => {
    if (!window.confirm('Cancel this appointment?')) return;
    try {
      await patientAPI.cancelAppointment(id);
      toast.success('Appointment cancelled');
      load();
    } catch (err) { toast.error(err.response?.data?.error || 'Failed to cancel'); }
  };

  const openReschedule = async (appt) => {
    setRescheduleModal(appt);
    setNewDate('');
    setNewTime('');
    setSlots([]);
  };

  const handleDateChange = async (date) => {
    setNewDate(date);
    setNewTime('');
    if (!date || !rescheduleModal) return;
    try {
      const res = await patientAPI.getSlots(rescheduleModal.doctor_id, date);
      setSlots(res.data);
    } catch {}
  };

  const handleReschedule = async () => {
    if (!newDate || !newTime) { toast.error('Pick a date and time'); return; }
    try {
      await patientAPI.rescheduleAppointment(rescheduleModal.id, {
        appointment_date: newDate, appointment_time: newTime
      });
      toast.success('Appointment rescheduled!');
      setRescheduleModal(null);
      load();
    } catch (err) { toast.error(err.response?.data?.error || 'Failed to reschedule'); }
  };

  const filters = [
    { key: 'all', label: 'All' },
    { key: 'Pending', label: 'Pending' },
    { key: 'Approved', label: 'Approved' },
    { key: 'Completed', label: 'Completed' },
    { key: 'Cancelled', label: 'Cancelled' },
  ];

  const shown = filter === 'all' ? appointments : appointments.filter(a => a.status === filter);
  const today = new Date().toISOString().split('T')[0];

  if (loading) return <div className="loading-center"><div className="spinner" /></div>;

  return (
    <div className="animate-fade">
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 28, marginBottom: 6 }}>📅 My Appointments</h1>
        <p style={{ color: 'var(--text-muted)' }}>View, reschedule or cancel your appointments</p>
      </div>

      {/* Filters */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 20, flexWrap: 'wrap' }}>
        {filters.map(f => (
          <button key={f.key}
            className={`btn btn-sm ${filter === f.key ? 'btn-primary' : 'btn-outline'}`}
            onClick={() => setFilter(f.key)}>
            {f.label}
            <span style={{ marginLeft: 6, background: 'rgba(255,255,255,0.25)', borderRadius: 99, padding: '0 6px', fontSize: 11 }}>
              {f.key === 'all' ? appointments.length : appointments.filter(a => a.status === f.key).length}
            </span>
          </button>
        ))}
      </div>

      {shown.length === 0 ? (
        <div className="card"><div className="empty-state">
          <div className="empty-icon">📋</div>
          <h3>No appointments</h3>
          <p>No {filter !== 'all' ? filter.toLowerCase() : ''} appointments found</p>
        </div></div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          {shown.map(a => (
            <div key={a.id} className="card" style={{ borderLeft: `4px solid ${
              a.status === 'Approved' ? 'var(--primary)' :
              a.status === 'Pending' ? 'var(--accent)' :
              a.status === 'Cancelled' ? 'var(--danger)' : 'var(--border)'
            }` }}>
              <div className="card-body" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: 12 }}>
                <div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 6 }}>
                    <span style={{ fontWeight: 700, fontSize: 16 }}>Dr. {a.doctor_name}</span>
                    <span className={`badge ${STATUS_BADGE[a.status]}`}>{a.status}</span>
                  </div>
                  <div style={{ color: 'var(--primary)', fontSize: 13, marginBottom: 4 }}>{a.doctor_specialization}</div>
                  <div style={{ display: 'flex', gap: 16, fontSize: 13, color: 'var(--text-muted)' }}>
                    <span>📅 {new Date(a.appointment_date).toLocaleDateString('en-IN', { weekday: 'short', day: 'numeric', month: 'long', year: 'numeric' })}</span>
                    <span>🕐 {a.appointment_time?.slice(0,5)}</span>
                  </div>
                  {a.reason && <div style={{ marginTop: 6, fontSize: 13, color: 'var(--text-muted)' }}>📝 {a.reason}</div>}
                  {a.treatment_details && (
                    <div style={{ marginTop: 8, padding: '8px 12px', background: 'var(--success-light)', borderRadius: 8, fontSize: 13 }}>
                      <strong>Treatment:</strong> {a.treatment_details}
                    </div>
                  )}
                </div>

                {!['Completed','Cancelled'].includes(a.status) && (
                  <div style={{ display: 'flex', gap: 8 }}>
                    <button className="btn btn-outline btn-sm" onClick={() => openReschedule(a)}>📅 Reschedule</button>
                    <button className="btn btn-danger btn-sm" onClick={() => handleCancel(a.id)}>✕ Cancel</button>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Reschedule Modal */}
      {rescheduleModal && (
        <div className="modal-overlay" onClick={() => setRescheduleModal(null)}>
          <div className="modal animate-slide" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>Reschedule Appointment</h3>
              <button className="modal-close" onClick={() => setRescheduleModal(null)}>×</button>
            </div>
            <div className="modal-body">
              <p style={{ color: 'var(--text-muted)', marginBottom: 16, fontSize: 14 }}>
                Current: {new Date(rescheduleModal.appointment_date).toLocaleDateString()} at {rescheduleModal.appointment_time?.slice(0,5)}
              </p>
              <div className="form-group">
                <label className="form-label">New Date *</label>
                <input className="form-control" type="date" min={today} value={newDate}
                  onChange={e => handleDateChange(e.target.value)} />
              </div>
              {slots.length > 0 && (
                <div className="form-group">
                  <label className="form-label">New Time *</label>
                  <div className="slots-grid">
                    {slots.map(s => (
                      <button key={s.time} className={`slot-btn ${newTime === s.time ? 'selected' : ''}`}
                        disabled={!s.available} onClick={() => setNewTime(s.time)}>{s.time}</button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="modal-footer">
              <button className="btn btn-outline" onClick={() => setRescheduleModal(null)}>Cancel</button>
              <button className="btn btn-primary" onClick={handleReschedule} disabled={!newDate || !newTime}>
                ✅ Confirm
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
